import asyncio
from aiocoap import *
from aiocoap import resource as coap_resource
import ssl

class SensorResource(coap_resource.Resource):
    def __init__(self):
        super().__init__()
        self.temperature = 25.0  # Example temperature value

    async def render_get(self, request):
        payload = str(self.temperature).encode('utf-8')
        return aiocoap.Message(code=CONTENT, payload=payload)

    async def render_put(self, request):
        self.temperature = float(request.payload.decode('utf-8'))
        return aiocoap.Message(code=CHANGED)

class ActuatorResource(coap_resource.Resource):
    def __init__(self):
        super().__init__()
        self.light_status = False  # Example light status

    async def render_get(self, request):
        payload = 'ON' if self.light_status else 'OFF'
        return aiocoap.Message(code=CONTENT, payload=payload.encode('utf-8'))

    async def render_put(self, request):
        self.light_status = request.payload.decode('utf-8').upper() == 'ON'
        return aiocoap.Message(code=CHANGED)

async def main():
    root = coap_resource.Site()
    root.add_resource(['sensors', 'temp'], SensorResource())
    root.add_resource(['actuators', 'light'], ActuatorResource())

    context = await Context.create_server_context(root, 
        bind=('::', 5683), 
        coap_server_cert='path/to/cert.pem', 
        coap_server_key='path/to/key.pem',
        ssl_context=ssl.create_default_context(ssl.Purpose.CLIENT_AUTH))

    print("CoAP server running...")
    await asyncio.get_running_loop().create_future()

if __name__ == "__main__":
    asyncio.run(main())